CREATE DEFINER=`root`@`127.0.0.1` PROCEDURE `sp_login` (IN `p_codigo_usuario` VARCHAR(6), IN `p_clave` TEXT, IN `p_ip` VARCHAR(39), OUT `p_respuesta` TEXT)  BEGIN

DECLARE v_usuario_existe BOOLEAN;
DECLARE v_id_usuario INT;
DECLARE v_clave TEXT;
DECLARE v_estatus TEXT;
DECLARE v_id_estatus INT;
DECLARE v_id_cargo INT;
DECLARE v_id_division INT;
DECLARE v_correo TEXT;
DECLARE v_estatus_denegado BOOLEAN;
DECLARE v_encrypt_iv TEXT;
DECLARE v_encrypt_key TEXT;
DECLARE v_sql_bitacora TEXT;
DECLARE v_fecha_login DATETIME;
DECLARE v_cambiar_clave BOOLEAN;

DECLARE v_custom_msg_error TEXT DEFAULT NULL;
DECLARE v_sql_string TEXT DEFAULT NULL;
DECLARE custom_error CONDITION FOR SQLSTATE '45000';

DECLARE EXIT HANDLER FOR SQLEXCEPTION, SQLWARNING
  BEGIN

    GET DIAGNOSTICS CONDITION 1 @code = RETURNED_SQLSTATE, @error_string = MESSAGE_TEXT;

    SELECT CONCAT('Error con el código ',@code,': ',@error_string) INTO v_custom_msg_error;

    ROLLBACK;

    CALL sp_mensaje_bd(1,1,"sp_login",v_custom_msg_error,NULL,1,@response);
    SET p_respuesta = '{
					  "message":"Ocurrió un error a la hora de autenticar al usuario!",
					  "response":false
					}';

    COMMIT;

  END;

DECLARE EXIT HANDLER FOR custom_error
	BEGIN

	  ROLLBACK;

	  IF v_custom_msg_error IS NOT NULL THEN
		CALL sp_mensaje_bd(1,1,"sp_login",v_custom_msg_error,v_sql_string,1,@response);
	  END IF;

	  IF p_respuesta = "" OR p_respuesta IS NULL THEN
		SET p_respuesta = '{
							"message":"Ocurrió un error a la hora de autenticar al usuario!",
							"response":false
						   }';
	  END IF;

	  COMMIT;

	END;

START TRANSACTION;

  SELECT IF(COUNT(1) > 0,TRUE, FALSE)
  INTO v_usuario_existe
  FROM tbl_usuario u
  WHERE u.codigo = p_codigo_usuario;

  IF v_usuario_existe > 0 THEN

     SELECT `iv`,
	        `key`
	 INTO v_encrypt_iv,
          v_encrypt_key
     FROM vw_config_encryption;

	 SELECT u.id,
			CAST(AES_DECRYPT(u.clave, v_encrypt_key) AS CHAR) AS clave,
            u.id_estatus,
            e.descripcion,
            IF(u.fecha_cambio_clave > CURDATE(), false, true) cambiar_clave,
            IFNULL(u.id_cargo,0),
            IFNULL(u.id_division,0),
            cu.correo_principal
	 INTO v_id_usuario,
          v_clave,
          v_id_estatus,
          v_estatus,
          v_cambiar_clave,
          v_id_cargo,
          v_id_division,
          v_correo
     FROM tbl_usuario u,
          tbl_estatus e,
          tbl_contacto_usuario cu
     WHERE u.codigo = p_codigo_usuario
     AND e.tabla = "tbl_usuario"
     AND e.valor = u.id_estatus
     AND u.id = cu.id_usuario;

     IF p_clave = v_clave THEN

		SELECT IF(COUNT(1) > 0,TRUE, FALSE)
		INTO v_estatus_denegado
		FROM tbl_estatus_login_denegado ed
		WHERE ed.id_estatus = v_id_estatus;

		IF v_estatus_denegado > 0 THEN

			SELECT CONCAT('{
                            "message"  : "El usuario está en estatus <b>',v_estatus,'</b>",
							"response" : false
							}') INTO p_respuesta;

			ROLLBACK;

		ELSE

            /* Obtenemos el valor anterior para la Bitácora */
			SELECT u.fecha_login, IFNULL(u.ip_login,"") INTO @fecha_login_anterior, @ip_login_anterior FROM tbl_usuario u WHERE u.id = v_id_usuario;
            SET @valor_anterior = CONCAT('{"fecha_login": "',@fecha_login_anterior,'", "ip_login": "',@ip_login_anterior,'"}');

            SELECT SYSDATE() INTO v_fecha_login;
            UPDATE tbl_usuario u SET u.fecha_login = v_fecha_login, u.ip_login = p_ip WHERE u.id = v_id_usuario;

            SELECT CONCAT('UPDATE tbl_usuario u SET u.fecha_login = "',v_fecha_login,'", u.ip_login = "',p_ip,'" WHERE u.id = ',v_id_usuario) INTO v_sql_bitacora;

            /* Indicamos el nuevo valor para la Bitácora */
            SET @nuevo_valor = CONCAT('{"fecha_login": "',v_fecha_login,'", "ip_login": "',p_ip,'"}');

			CALL sp_bitacora(2,"login",v_id_usuario,v_id_usuario,"tbl_usuario",v_sql_bitacora,@valor_anterior,@nuevo_valor,p_ip,@response);

            SET @v_respuesta_otro_sp = JSON_UNQUOTE(JSON_EXTRACT(@response,'$.response'));

            IF @v_respuesta_otro_sp = "true" THEN

				SELECT CONCAT('{
                                "cambiar_clave"  : ',v_cambiar_clave,',
                                "id_cargo"       : ',v_id_cargo,',
                                "id_division"    : ',v_id_division,',
								"id_usuario"     : ',v_id_usuario,',
                                "correo_usuario" : "',v_correo,'",
								"message"        : "Bienvenido!, espere unos segundo mientras mientras es redireccionado.",
								"response"       : true
							   }') INTO p_respuesta;

				COMMIT;

			ELSE

                SET p_respuesta = '{
									"message":"Ocurrió un error a la hora de autenticar al usuario, no se pudo registrar en Bitácora!",
									"response":false
								   }';

				ROLLBACK;

			END IF;

		END IF;

     ELSE

        SET p_respuesta = '{
							"message":"Contraseña inválida",
							"response":false
						   }';

        ROLLBACK;

     END IF;

  ELSE

    SET p_respuesta = '{
						"message":"El usuario no existe!",
						"response":false
					   }';

	ROLLBACK;

  END IF;

END$$

CREATE DEFINER=`root`@`127.0.0.1` PROCEDURE `sp_mensaje_bd` (IN `p_id_tipo_objeto_bd` INT, IN `p_id_tipo_mensaje_bd` INT, IN `p_nombre_objeto` VARCHAR(50), IN `p_mensaje` TEXT, IN `p_consulta_sql` TEXT, IN `p_id_estatus` INT, OUT `p_respuesta` TEXT)  BEGIN

  DECLARE v_fecha DATETIME;
  DECLARE v_id_tipo_objeto_bd_existe INT;
  DECLARE v_id_tipo_mensaje_bd_existe INT;
  DECLARE v_id_estatus_existe INT;
  DECLARE v_msg_error TEXT;
  DECLARE custom_error CONDITION FOR SQLSTATE '45000';
  DECLARE EXIT HANDLER FOR SQLEXCEPTION, SQLWARNING
    BEGIN

      GET DIAGNOSTICS CONDITION 1 @code = RETURNED_SQLSTATE, @error_string = MESSAGE_TEXT;

      SELECT CONCAT('{"response": false, "message": "Error con el código ',@code,': ',@error_string,'"}') INTO p_respuesta;

    END;
  DECLARE EXIT HANDLER FOR custom_error
    BEGIN
      SET p_respuesta = v_msg_error;
    END;

  SELECT COUNT(1) INTO v_id_tipo_objeto_bd_existe FROM tbl_tipo_mensaje_bd WHERE id = p_id_tipo_objeto_bd;

  SELECT COUNT(1) INTO v_id_tipo_mensaje_bd_existe FROM tbl_tipo_mensaje_bd WHERE id = p_id_tipo_mensaje_bd;

  SELECT COUNT(1) INTO v_id_estatus_existe FROM tbl_estatus WHERE tabla = "tbl_mensaje_bd" AND valor = p_id_estatus;

  # Evaluamos si algun parametro es inválido
  IF v_id_tipo_objeto_bd_existe = 0 THEN

    SELECT CONCAT('{"response":false, "message":"Ocurrió un error el parametro de entrada ID_TIPO_OBJECTO_BD, al parecer el ID con el valor ',p_id_tipo_objeto_bd,' no existe."}') INTO v_msg_error;
    SIGNAL SQLSTATE '45000';

  ELSEIF v_id_tipo_mensaje_bd_existe = 0 THEN

    SELECT CONCAT('{"response":false, "message":"Ocurrió un error el parametro de entrada ID_TIPO_MENSAJE_BD, al parecer el ID con el valor ',p_id_tipo_mensaje_bd,' no existe."}') INTO v_msg_error;
    SIGNAL SQLSTATE '45000';

  ELSEIF v_id_estatus_existe = 0 THEN

    SELECT CONCAT('{"response":false, "message":"Ocurrió un error el parametro de entrada ID_ESTATUS, al parecer el ID DEL ESTATUS con el valor ',p_id_estatus,' no existe."}') INTO v_msg_error;
    SIGNAL SQLSTATE '45000';

  END IF;

  SELECT SYSDATE() INTO v_fecha;

  INSERT `tbl_mensaje_bd`(`id_tipo_objeto_bd`,`id_tipo_mensaje_bd`,`nombre_objeto`,`mensaje`,`fecha`,`consulta_sql`,`id_estatus`) VALUES (p_id_tipo_objeto_bd, p_id_tipo_mensaje_bd, p_nombre_objeto, p_mensaje, v_fecha, p_consulta_sql, p_id_estatus);

  SET p_respuesta = '{"response": true, "message": "Mensaje generado con éxito"}';

END$$

CREATE DEFINER=`root`@`127.0.0.1` PROCEDURE `sp_nuevo_cliente` (IN `p_id_usuario` INT, IN `p_id_usuario_socio` INT, IN `p_codigo_cliente` INT, IN `p_rif` VARCHAR(30), IN `p_razon_social` VARCHAR(60), IN `p_id_pais` INT, IN `p_direccion` TEXT, IN `p_telefono_fiscal` VARCHAR(30), IN `p_pagina_web` VARCHAR(150), IN `p_email_fiscal` VARCHAR(100), IN `p_ip_accion` VARCHAR(40), OUT `p_respuesta` TEXT)  BEGIN
DECLARE v_fecha_creacion_cliente DATE;
DECLARE v_sql_bitacora TEXT;

DECLARE v_custom_msg_error TEXT DEFAULT NULL;
DECLARE v_sql_string TEXT DEFAULT NULL;
DECLARE custom_error CONDITION FOR SQLSTATE '45000';

DECLARE EXIT HANDLER FOR SQLEXCEPTION, SQLWARNING
    BEGIN 
      
        GET DIAGNOSTICS CONDITION 1 @code = RETURNED_SQLSTATE, @error_string = MESSAGE_TEXT;
        SELECT CONCAT('Error con el código ',@code,': ',@error_string) INTO v_custom_msg_error; 
        
        ROLLBACK;
        
        CALL sp_mensaje_bd(1,1,"sp_nuevo_cliente",v_custom_msg_error,NULL,1,@response);
        SET p_respuesta = '{ 
          "message":"Ocurrió un error a la hora de crear el cliente!",
      	  "response": false
    	}';
      COMMIT;  
  END;
  DECLARE EXIT HANDLER FOR custom_error 
    BEGIN
      ROLLBACK;
        IF v_custom_msg_error IS NOT NULL THEN
          CALL sp_mensaje_bd(1,1,"sp_nuevo_cliente",v_custom_msg_error,v_sql_string,1,@response);
        END IF;
        IF p_respuesta = "" OR p_respuesta IS NULL THEN
          SET p_respuesta = '{
            "message": "Ocurrió un error a la hora tratar de actualizar su contraseña!",
            "response": false
      }';
        END IF;
      COMMIT;
  END;
  START TRANSACTION;
SELECT DATE_ADD(CURDATE(), INTERVAL 60 DAY) INTO v_fecha_creacion_cliente;
SET v_sql_bitacora = CONCAT('INSERT INTO tbl_cliente (id, id_usuario_socio, codigo, rif, nit, razon_social, id_pais, direccion, telefono_fiscal, pagina_web, email_fiscal, id_estatus) VALUES (null, "',p_id_usuario_socio,'", "',p_codigo_cliente,'", "',p_rif,'", null, "',p_razon_social,'", "',p_id_pais,'", "',p_direccion,'", "',p_telefono_fiscal,'", "',p_pagina_web,'", "',p_email_fiscal,'", 1)');
SET @nuevo_valor = CONCAT('{"id_usuario_socio": "',p_id_usuario_socio,'", "codigo": "',p_codigo_cliente,'", "rif": "',p_rif,'", "razon_social": "',p_razon_social,'", "id_pais": "',p_id_pais,'", "direccion": "',p_direccion,'", "telefono_fiscal": "',p_telefono_fiscal,'", "pagina_web": "',p_pagina_web,'", "email_fiscal": "',p_email_fiscal,'", "id_estatus": ",1,"}');
CALL sp_bitacora(1,"crear_cliente",p_id_usuario,p_id_usuario,"tbl_cliente",v_sql_bitacora,@valor_anterior,@nuevo_valor,p_ip_accion,@response);
SET @v_respuesta_otro_sp = JSON_UNQUOTE(JSON_EXTRACT(@response,'$.response'));
IF @v_respuesta_otro_sp = "true" THEN
SET p_respuesta = CONCAT('{
"message": "Cliente Creado con Éxito.",
"response":true
}');
COMMIT;
ELSE
SET p_respuesta = '{
"message":"Ocurrió un error a la hora de crear el cliente, no se pudo registrar en Bitácora!",
"response":false
}';
ROLLBACK;
END IF;
END$$

CREATE DEFINER=`root`@`127.0.0.1` PROCEDURE `sp_recuperar_login` (IN `p_codigo_usuario` VARCHAR(6), IN `p_ip` VARCHAR(39), OUT `p_respuesta` TEXT)  BEGIN

	DECLARE v_usuario_existe BOOLEAN;
    DECLARE v_correo_principal TEXT;
    DECLARE v_id_usuario INT;
    DECLARE v_clave TEXT;
    DECLARE v_sql_bitacora TEXT;

    DECLARE v_custom_msg_error TEXT DEFAULT NULL;
    DECLARE v_sql_string TEXT DEFAULT NULL;
    DECLARE custom_error CONDITION FOR SQLSTATE '45000';
    DECLARE EXIT HANDLER FOR SQLEXCEPTION, SQLWARNING
      BEGIN

        GET DIAGNOSTICS CONDITION 1 @code = RETURNED_SQLSTATE, @error_string = MESSAGE_TEXT;

        SELECT CONCAT('Error con el código ',@code,': ',@error_string) INTO v_custom_msg_error;
	
		ROLLBACK;
    
        CALL sp_mensaje_bd(1,1,"sp_recuperar_login",v_custom_msg_error,NULL,1,@response);
        SET p_respuesta = '{
                            "message":"Ocurrió un error a la hora de recuperar la contraseña del usuario!",
                            "response":false
						   }';

        COMMIT;

    END;
  DECLARE EXIT HANDLER FOR custom_error
    BEGIN

	  ROLLBACK;

      IF v_custom_msg_error IS NOT NULL THEN
        CALL sp_mensaje_bd(1,1,"sp_recuperar_login",v_custom_msg_error,v_sql_string,1,@response);
      END IF;

      IF p_respuesta = "" OR p_respuesta IS NULL THEN
        SET p_respuesta = '{
                            "message":"Ocurrió un error a la hora de recuperar la contraseña del usuario!",
                            "response":false
						   }';
	  END IF;

	  COMMIT;

    END;

  START TRANSACTION;

  SELECT IF(COUNT(1) > 0,TRUE, FALSE)
  INTO v_usuario_existe
  FROM tbl_usuario u
  WHERE u.codigo = p_codigo_usuario;

  IF v_usuario_existe > 0 THEN

     SELECT `key`
	 INTO @v_encrypt_key
     FROM vw_config_encryption;

	SELECT cu.correo_principal,
           u.id,
           CAST(AES_DECRYPT(u.clave, @v_encrypt_key) AS CHAR) AS clave
	INTO v_correo_principal,
         v_id_usuario,
         v_clave
    FROM tbl_usuario u,
		 tbl_contacto_usuario cu
    WHERE u.id = cu.id_usuario
    AND u.codigo = p_codigo_usuario;

    SELECT CONCAT('SELECT cu.correo_principal,
                          u.id,
                          CAST(AES_DECRYPT(u.clave, "',@v_encrypt_key,'") AS CHAR) AS clave
				   FROM tbl_usuario u,
						tbl_contacto_usuario cu
                   WHERE u.id = cu.id_usuario
                   AND u.codigo = "',p_codigo_usuario,'"') INTO v_sql_bitacora;

    CALL sp_bitacora(4,"recuperar_clave",v_id_usuario,v_id_usuario,"tbl_usuario",v_sql_bitacora,"","",p_ip,@response);

    SET p_respuesta = CONCAT('{
						"correo": "',v_correo_principal,'",
                        "clave": "',v_clave,'",
						"response":true
					   }');

	COMMIT;

  ELSE

    SET p_respuesta = '{
						"message":"El usuario no existe!",
						"response":false
					   }';

	ROLLBACK;

  END IF;

END$$

CREATE DEFINER=`root`@`127.0.0.1` PROCEDURE `sp_resetar_claves_usuarios` (OUT `p_respuesta` TEXT)  BEGIN

  DECLARE v_custom_msg_error TEXT DEFAULT NULL;
  DECLARE v_sql_string TEXT DEFAULT NULL;
  DECLARE custom_error CONDITION FOR SQLSTATE '45000';

  DECLARE EXIT HANDLER FOR SQLEXCEPTION, SQLWARNING
      BEGIN

        GET DIAGNOSTICS CONDITION 1 @code = RETURNED_SQLSTATE, @error_string = MESSAGE_TEXT;

        SELECT CONCAT('Error con el código ',@code,': ',@error_string) INTO v_custom_msg_error;

		ROLLBACK;

        CALL sp_mensaje_bd(1,1,"sp_resetar_claves_usuarios",v_custom_msg_error,NULL,1,@response);
        SET p_respuesta = '{
                            "message":"Ocurrió un error a la hora de actualizar las contraseñas!",
                            "response":false
						   }';

        COMMIT;

    END;
  DECLARE EXIT HANDLER FOR custom_error
    BEGIN

	  ROLLBACK;

      IF v_custom_msg_error IS NOT NULL THEN
        CALL sp_mensaje_bd(1,1,"sp_resetar_claves_usuarios",v_custom_msg_error,v_sql_string,1,@response);
      END IF;

      IF p_respuesta = "" OR p_respuesta IS NULL THEN
        SET p_respuesta = '{
                            "message":"Ocurrió un error a la hora de actualizar las contraseñas!",
                            "response":false
						   }';
	  END IF;

	  COMMIT;

    END;

  START TRANSACTION;

  SET @llave = (SELECT c.valor FROM tbl_configuracion c WHERE c.nombre = "encrypt-key");
  SET @fecha = CURDATE();

  SET SQL_SAFE_UPDATES = 0;

  UPDATE tbl_usuario u2
  INNER JOIN (
		SELECT AES_ENCRYPT(udi.documento, @llave) AS clave,
			   u.id AS id
		FROM tbl_usuario u,
			 tbl_usuario_documento_identidad udi,
			 tbl_tipo_documento_identidad tdi
		WHERE u.id = udi.id_usuario
		AND udi.id_tipo_documento_identidad = tdi.id
   ) AS t2 ON t2.id = u2.id
   SET u2.clave = t2.clave,
       u2.fecha_cambio_clave = @fecha;

   SET p_respuesta = '{
						"message":"Contraseñas actualizadas!",
						"response":true
			          }';

   SET SQL_SAFE_UPDATES = 1;

   COMMIT;

END$$

CREATE DEFINER=`root`@`127.0.0.1` PROCEDURE `sp_usuario_cambia_su_clave` (IN `p_id_usuario` INT, IN `p_clave_actual` TEXT, IN `p_nueva_clave` TEXT, IN `p_ip_accion` VARCHAR(39), OUT `p_respuesta` TEXT)  BEGIN

  DECLARE v_clave_actual_bd TEXT;
  DECLARE v_fecha_cambio_clave DATE;
  DECLARE v_sql_bitacora TEXT;

  DECLARE v_custom_msg_error TEXT DEFAULT NULL;
  DECLARE v_sql_string TEXT DEFAULT NULL;
  DECLARE custom_error CONDITION FOR SQLSTATE '45000';

  DECLARE EXIT HANDLER FOR SQLEXCEPTION, SQLWARNING
    BEGIN

      GET DIAGNOSTICS CONDITION 1 @code = RETURNED_SQLSTATE, @error_string = MESSAGE_TEXT;

      SELECT CONCAT('Error con el código ',@code,': ',@error_string) INTO v_custom_msg_error;
	  
      ROLLBACK;
      
      CALL sp_mensaje_bd(1,1,"sp_usuario_cambia_su_clave",v_custom_msg_error,NULL,1,@response);
	  SET p_respuesta = '{
						  "message":"Ocurrió un error a la hora tratar de actualizar su contraseña!",
						  "response": false
						 }';

	   COMMIT;

    END;
  DECLARE EXIT HANDLER FOR custom_error
    BEGIN

      ROLLBACK;

	  IF v_custom_msg_error IS NOT NULL THEN
        CALL sp_mensaje_bd(1,1,"sp_usuario_cambia_su_clave",v_custom_msg_error,v_sql_string,1,@response);
      END IF;

      IF p_respuesta = "" OR p_respuesta IS NULL THEN
        SET p_respuesta = '{
                            "message": "Ocurrió un error a la hora tratar de actualizar su contraseña!",
                            "response": false
						   }';
	  END IF;

      COMMIT;

    END;

    START TRANSACTION;

    SELECT `key`
	INTO @v_encrypt_key
	FROM vw_config_encryption;

    SELECT CAST(AES_DECRYPT(u.clave, @v_encrypt_key) AS CHAR) AS clave
    INTO v_clave_actual_bd
    FROM tbl_usuario u
    WHERE u.id = p_id_usuario;

    IF p_clave_actual = v_clave_actual_bd THEN

        /* Obtenemos el valor anterior para la Bitácora */
	    SELECT IFNULL(u.fecha_cambio_clave,"") INTO @v_fecha_cambio_clave_anterior FROM tbl_usuario u WHERE u.id = p_id_usuario;
        SET @valor_anterior = CONCAT('{"clave": "########", "fecha_cambio_clave": "',@v_fecha_cambio_clave_anterior,'"}');

        SELECT valor
		INTO @v_dias
		FROM tbl_configuracion
        WHERE nombre = "dias_cambio_clave";

        SELECT DATE_ADD(CURDATE(), INTERVAL 60 DAY) INTO v_fecha_cambio_clave;

		UPDATE tbl_usuario u SET u.clave = AES_ENCRYPT(p_nueva_clave, @v_encrypt_key), u.fecha_cambio_clave = v_fecha_cambio_clave WHERE u.id = p_id_usuario;

		SET v_sql_bitacora = CONCAT('UPDATE tbl_usuario u SET u.clave = "########", u.fecha_cambio_clave = "',v_fecha_cambio_clave,'" WHERE u.id = ',p_id_usuario);

        /* Indicamos el nuevo valor para la Bitácora */
		SET @nuevo_valor = CONCAT('{"clave": "########", "fecha_cambio_clave": "',v_fecha_cambio_clave,'"}');

        CALL sp_bitacora(2,"cambio_clave_usuario",p_id_usuario,p_id_usuario,"tbl_usuario",v_sql_bitacora,@valor_anterior,@nuevo_valor,p_ip_accion,@response);

		SET @v_respuesta_otro_sp = JSON_UNQUOTE(JSON_EXTRACT(@response,'$.response'));

		IF @v_respuesta_otro_sp = "true" THEN

			SET p_respuesta = CONCAT('{
										"message": "Contraseña actualizada con éxito!",
										"response":true
									   }');

			COMMIT;

        ELSE

            SET p_respuesta = '{
								"message":"Ocurrió un error a la hora de actualizar la contraseña, no se pudo registrar en Bitácora!",
								"response":false
							   }';

			ROLLBACK;

        END IF;

    ELSE

        SET p_respuesta = CONCAT('{
									"message": "La contraseña actual es inválida!",
									"response":false
								   }');

		COMMIT;

    END IF;

END$$

DELIMITER ;

